elements.text:
.overlap-grid {
  display: grid;
  grid-template-columns: repeat(5, 1fr);  /* 5 equal columns */
  grid-template-rows:    repeat(3, 52px); /* 3 fixed-height rows */
  gap: 6px;
}

/* Each child picks its own grid area — they CAN overlap */

.bg-block {
  grid-column: 1 / 4;  /* cols 1 → 3 */
  grid-row:    1 / 3;  /* rows 1 → 2 */
  opacity: .6;         /* sits "behind" */
}

.fg-card {
  grid-column: 2 / 5;  /* overlaps bg-block on col 2–3 */
  grid-row:    2 / 4;  /* overlaps bg-block on row 2   */
  z-index: 1;          /* render on top */
}

.side {
  grid-column: 5;       /* single col, shorthand for 5/6 */
  grid-row:    1 / 4;   /* spans all 3 rows */
}

.top-r {
  grid-column: 4 / 6;  /* cols 4–5 */
  grid-row:    1;      /* row 1 only */
}

.btm-l {
  grid-column: 1;       /* col 1 only */
  grid-row:    3;       /* row 3 only */
}

